class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        vector<int> people(n, 1e9);
        people[0] = 0;
        people[firstPerson] = 0;
        sort(meetings.begin(), meetings.end(), [](vector<int>& a, vector<int>& b) {
            return a[2] < b[2];
        });
        for (auto& meeting : meetings) {
            for (int person : {meeting[0], meeting[1]}) {
                people[person] = min(people[person], meeting[2]);
            }
        }
        vector<int> result;
        for (int i = 0; i < n; i++) {
            if (people[i] != 1e9) result.push_back(i);
        }
        return result;
    }
};
